// Парсим CSV, считаем агрегаты за последние 7 дней и сравниваем с предыдущей неделей.
const raw = $('Тянем Garmin CSV').item.json.data || $('Тянем Garmin CSV').item.json;

function parseCsv(text) {
  if (typeof text !== 'string') text = String(text);
  const lines = text.split(/\r?\n/).filter(Boolean);
  if (!lines.length) return [];
  const splitLine = (s) => s.match(/("([^"]|"")*"|[^,]*)(,|$)/g)
    .filter(Boolean)
    .map(v => v.replace(/,$/, '').replace(/^"|"$/g, '').replace(/""/g, '"').trim());
  const headers = splitLine(lines[0]);
  return lines.slice(1).map(line => {
    const cells = splitLine(line);
    const obj = {};
    headers.forEach((h, i) => { obj[h] = cells[i] ?? ''; });
    return obj;
  });
}

function num(v) {
  if (v == null || v === '') return NaN;
  if (typeof v === 'number') return v;
  const cleaned = String(v).replace(/[\s\u00A0]/g, '').replace(',', '.');
  const n = parseFloat(cleaned);
  return isFinite(n) ? n : NaN;
}

const rows = parseCsv(raw)
  .filter(r => r.date)
  .sort((a, b) => (a.date || '').localeCompare(b.date || ''));

const lastWeek = rows.slice(-7);
const prevWeek = rows.slice(-14, -7);

function stats(weekRows, key) {
  const nums = weekRows.map(r => num(r[key])).filter(v => isFinite(v));
  if (!nums.length) return null;
  const sum = nums.reduce((a, b) => a + b, 0);
  return {
    avg: sum / nums.length,
    min: Math.min(...nums),
    max: Math.max(...nums),
    count: nums.length,
  };
}

function delta(current, previous) {
  if (!current || !previous) return null;
  return current.avg - previous.avg;
}

const keys = ['sleep_hours', 'sleep_score', 'hrv_last_night', 'steps', 'stress_avg', 'body_battery_max'];
const summary = {};
for (const k of keys) {
  const cur = stats(lastWeek, k);
  const prev = stats(prevWeek, k);
  summary[k] = {
    current: cur ? Number(cur.avg.toFixed(1)) : null,
    previous: prev ? Number(prev.avg.toFixed(1)) : null,
    delta: cur && prev ? Number((cur.avg - prev.avg).toFixed(1)) : null,
    min: cur ? Number(cur.min.toFixed(1)) : null,
    max: cur ? Number(cur.max.toFixed(1)) : null,
  };
}

const payload = {
  week_start: lastWeek[0]?.date || null,
  week_end: lastWeek[lastWeek.length - 1]?.date || null,
  days_count: lastWeek.length,
  summary,
};

return [{ json: payload }];

